for p in ['model.py','train.py','predict.py']:
    txt=Path(p).read_text().splitlines()
    print(f'===== {p} nlines={len(txt)} =====')
    if p=='model.py':
        ranges=[(1,min(len(txt),220))]
    elif p=='train.py':
        ranges=[(1,90),(90,190),(190,min(len(txt),320))]
    else:
        ranges=[(1,min(len(txt),120))]
    for a,b in ranges:
        print(f'--- lines {a}-{b} ---')
        for i in range(a,b+1):
            if i<=len(txt): print(f'{i:03d}: {txt[i-1]}')
